export function parseConfig(raw: string): Record<string, string> {
  return Object.fromEntries(raw.split('\n').map(l => l.split('=')));
}

export function validateConfig(cfg: Record<string, string>): boolean {
  return Object.keys(cfg).every(k => k.length > 0);
}

