export function applyEnvOverrides(cfg: Record<string, string>): Record<string, string> {
  const result = { ...cfg };
  for (const key of Object.keys(result)) {
    const envKey = `CONFIG_${key.toUpperCase()}`;
    if (process.env[envKey]) result[key] = process.env[envKey]!;
  }
  return result;
}

